def create_invoice(customer, items, use_new_pricing=False):
    previous = None
    if use_new_pricing:
        previous = is_enabled("new_pricing")
        enable("new_pricing")

    try:
        total = 0
        lines = []
        for item in items:
            price = compute_price(item["base"], item["qty"])
            lines.append({"sku": item["sku"], "amount": price})
            total += price

        invoice = {
            "customer": customer,
            "lines": lines,
            "total": total,
            "pricing_version": get_pricing_version(),
        }

        if is_enabled("audit_mode"):
            invoice["audit"] = True
            _invoices.append(invoice)

        return invoice
    finally:
        if use_new_pricing and previous is not None:
            if previous:
                enable("new_pricing")
            else:
                disable("new_pricing")


