_initialized = False
_buffer = []


def reset():
    global _initialized
    _log.clear()
    _buffer.clear()
    _initialized = False


def init():
    global _initialized
    _initialized = True
    _log.append("init")
    for item in _buffer:
        _log.append(f"processed:{item}")
    _buffer.clear()


def process(item):
